#include<bits/stdc++.h>
using namespace std;
long long a,b,c;
long long aa[105][105],bb[105][105],cc[105][105];
int main() {
	cin>>a>>b>>c;
	for(int i=1; i<=a; i++) {
		for(int j=1; j<=b; j++) {
			cin>>aa[i][j];
		}
	}
	for(int i=1; i<=b; i++) {
		for(int j=1; j<=c; j++) {
			cin>>bb[i][j];
		}
	}
	for(int i=1; i<=a; i++) {
		for(int j=1; j<=c; j++) {
			for(int z=1; z<=b; z++) {
				cc[i][j]+=aa[i][z]*bb[z][j];
			}
		}
	}
	for(int i=1; i<=a; i++) {
		for(int j=1; j<=c; j++) {
			cout<<cc[i][j]<<" ";
		}
		cout<<"\n";
	}
	return 0;
}
